let allData = {{workflowparams:allData}}
const updatedSM = []
const saveAs = {{workflowparams:saveAs}}

// Helper function to format qty and price fields to 3 decimal places
const formatNumber = (value) => {
  if (value === null || value === undefined || value === "") return 0;
  return parseFloat(value).toFixed(3);
};

for (const [index, smLineItem] of allData.stock_movement.entries()) {
  // Format qty and price fields
  smLineItem.received_quantity = formatNumber(smLineItem.received_quantity);
  smLineItem.unit_price = formatNumber(smLineItem.unit_price);
  smLineItem.amount = formatNumber(smLineItem.amount);

  smLineItem.organization_id = allData.organization_id;
  smLineItem.issuing_plant = allData.issuing_operation_faci || null;
  smLineItem.receiving_plant = allData.receiving_operation_faci || null;
  smLineItem.line_index = index + 1;

  updatedSM.push(smLineItem)
}

allData.stock_movement = updatedSM;

if ({{workflowparams:pageStatus}} === "Add") {
  allData.stock_movement_status = "Draft";
}

if (saveAs === "Draft") {
  if (
    allData.stock_movement_no_type !== -9999 &&
    (!allData.stock_movement_no ||
      allData.stock_movement_no === null ||
      allData.stock_movement_no === "")
  ) {
    allData.stock_movement_no = "draft";
  }
} else {
  if (
    allData.stock_movement_no_type !== -9999 &&
    (!allData.stock_movement_no ||
      allData.stock_movement_no === null ||
      allData.stock_movement_no === "" ||
      allData.stock_movement_status !== "In Progress")
  ) {
    allData.stock_movement_no = "issued";
  }
}

if (allData.acc_integration_type !== "No Accounting Integration") {
  allData.posted_status = "Unposted";
} else {
  allData.posted_status = "";
}

return {
  allData: allData,
  stock_movement_status: allData.stock_movement_status,
  acc_integration_type: allData.acc_integration_type,
};

return {
  required_fields: JSON.stringify([
  { name: "stock_movement_no", label: "Stock Movement No" },
  { name: "movement_type", label: "Movement Type" },
  { name: "issue_date", label: "Issue Date" },
  { name: "issuing_operation_faci", label: "Issuing Operation Facility" },
  {
    name: "stock_movement",
    label: "Item Information",
    isArray: true,
    arrayType: "object",
    arrayFields: [],
  },
]),
  data: JSON.stringify({
    stock_movement_no: {{node:code_node_oW7T9VBW.data.allData.stock_movement_no}},
    movement_type: {{node:code_node_oW7T9VBW.data.allData.movement_type}},
    issue_date: {{node:code_node_oW7T9VBW.data.allData.issue_date}},
    issuing_operation_faci: {{node:code_node_oW7T9VBW.data.allData.issuing_operation_faci}},
    stock_movement: {{node:code_node_oW7T9VBW.data.allData.stock_movement}}
  })
}

const allData = {{node:code_node_oW7T9VBW.data.allData}}
const subformData = allData.stock_movement

let locationFailed = 0;
let quantityFailed = 0;
let categoryFailed = 0;
let locationMessage
let quantityMessage
let categoryMessage

for (let i = 0; i < subformData.length; i++) {
  const item = subformData[i];

  // Skip split parent rows
  if (item.is_split === "Yes" && item.parent_or_child === "Parent") {
    continue;
  }

  if (!item.location_id) {
    locationFailed = 1;
    locationMessage = `Location ID is required for item ${i + 1} in Miscellaneous Receipt`
    break;
  }
}

for (let i = 0; i < subformData.length; i++) {
  const item = subformData[i];

  // Skip split parent rows
  if (item.is_split === "Yes" && item.parent_or_child === "Parent") {
    continue;
  }

  if (!item.received_quantity || item.received_quantity <= 0) {
    quantityFailed = 1;
    quantityMessage = `Quantity is required for item ${i + 1} in Miscellaneous Receipt`
    break;
  }
}

for (let i = 0; i < subformData.length; i++) {
  const item = subformData[i];

  // Skip split parent rows
  if (item.is_split === "Yes" && item.parent_or_child === "Parent") {
    continue;
  }

  if (!item.category) {
    categoryFailed = 1;
    categoryMessage = `Category is required for item ${i + 1} in Miscellaneous Receipt`
    break;
  }
}


return {
  locationFailed: locationFailed,
  quantityFailed: quantityFailed,
  categoryFailed: categoryFailed,
  locationMessage: locationMessage,
  quantityMessage: quantityMessage,
  categoryMessage: categoryMessage
};

const allData = {{node:code_node_oW7T9VBW.data.allData}};
const subformData = allData.stock_movement || [];
const currentIndexRaw = {{node:get_cache_node_BGIDXget.data}};
const index = currentIndexRaw ? parseInt(currentIndexRaw, 10) : 0;
const item = subformData[index] || {};

// Only generate for auto-batch rows that are NOT hierarchy children
const needsGen = (item.batch_id === "Auto-generated batch number" && item.parent_or_child !== "Child") ? 1 : 0;

return {
  item_id: item.item_selection || "",
  needsGen: needsGen,
  index: index,
  nextIndex: index + 1
};

const data = {{node:workflow_node_GenBatch.data}} || {};
const batchNumber = data.batch_number || "";
const isError = batchNumber ? 0 : 1;
const message = data.message || data.msg || "Failed to generate batch number. Please ensure a Batch Number Configuration is set up for this item or organization.";

return { batchNumber, isError, message };

const arr = JSON.parse({{node:get_cache_node_BGARRget.data}}) || [];
const index = {{node:code_node_BatchGenPrep.data.index}};
const batchNumber = {{node:code_node_NormalizeBatch.data.batchNumber}};

arr.push({ index: index, batch_number: batchNumber });

return { generatedBatches: arr };

const allData = {{node:code_node_oW7T9VBW.data.allData}};
const tableSM = allData.stock_movement || [];
const generated = JSON.parse({{node:get_cache_node_BGARRfinal.data}}) || [];

// Overlay generated batch numbers onto their rows by index
const genMap = {};
for (const g of generated) {
  genMap[g.index] = g.batch_number;
}
for (let i = 0; i < tableSM.length; i++) {
  if (genMap[i] !== undefined && genMap[i] !== null) {
    tableSM[i].batch_id = genMap[i];
  }
}

// Hierarchy children inherit parent batch number + dates
for (const item of tableSM) {
  if (item.parent_or_child === "Child") {
    const parentRow = tableSM.find(
      (row) =>
        row.is_split === "Yes" &&
        row.parent_or_child === "Parent" &&
        row.parent_index === item.parent_index
    );
    if (parentRow) {
      item.batch_id = parentRow.batch_id;
      item.manufacturing_date = parentRow.manufacturing_date;
      item.expired_date = parentRow.expired_date;
    }
  }
}

// Recalc hierarchy parent received_quantity from children + amount
for (const item of tableSM) {
  if (item.is_split === "Yes" && item.parent_or_child === "Parent") {
    const children = tableSM.filter(
      (row) =>
        row.parent_or_child === "Child" &&
        row.parent_index === item.parent_index
    );
    const totalChildQty = children.reduce(
      (sum, c) => sum + (parseFloat(c.received_quantity) || 0), 0);
    item.received_quantity = parseFloat(totalChildQty.toFixed(3));
    item.amount = item.received_quantity * (item.unit_price || 0);
  }
}

return { stock_movement: tableSM };

