const doc_date = allData.issue_date;

const item = subformData[index];
const material_id = item.item_selection;
const material_uom = item.received_quantity_uom || item.quantity_uom;
const quantity = item.received_quantity;
const unit_price = item.unit_price;
const storage_location_id = item.storage_location_id;
const location_id = item.location_id;
const batch_id = item.batch_id || null;
const remark = item.item_remark || null;
const remark2 = item.item_remark_2 || null;
const remark3 = item.item_remark_3 || null;
const inventory_category = item.category || "Unrestricted";
const manufacturing_date = item.manufacturing_date || null;
const expired_date = item.expired_date || null;
const referenceNo = item.reference_no || null;

return {
  plant_id: plant_id,
  organization_id: organization_id,
  stock_movement_no: stock_movement_no,
  page_status: page_status,
  material_id: material_id,
  material_uom: material_uom,
  quantity: quantity,
  unit_price: unit_price,
  storage_location_id: storage_location_id,
  location_id: location_id,
  batch_id: batch_id,
  inventory_category: inventory_category,
  doc_date: doc_date,
  remark: remark,
  remark2: remark2,
  remark3: remark3,
  referenceNo: referenceNo,
  index: index,
  nextIndex: index + 1,
  manufacturing_date: manufacturing_date,
  expired_date: expired_date,
  item: item,
  is_split: item.is_split || "",
  parent_or_child: item.parent_or_child || "",
  parent_index: item.parent_index || 0,
};

const rawBatch = {{node:add_node_EqJT1dUp.data}} || []
const batchId = rawBatch[0].id

return {
  batchId
}

let batchId = {{node:get_cache_node_ImHbBe9y.data}};

if (!batchId || batchId === '' || batchId === 'null' || batchId === 'undefined') {
  batchId = null;
}

return {
